<body>

    <div class="container">
        <h1>Çekiliş Uygulaması</h1>

        <div class="controls">
            <button id="btnDraw" onclick="cekilisYap()">Çekiliş Yap</button>
            <button id="btnFinish" onclick="cekilisiBitir()">Çekilişi Bitir</button>
        </div>

        <div id="resultsArea">
            <p style="color: #aaa; text-align: center;">Çekiliş sonuçları burada görünecek...</p>
        </div>

        <div id="frequencyReport">
            <h3>Sayı Frekans Raporu</h3>
            <div class="freq-grid" id="freqGrid"></div>
        </div>

        <button id="btnDownload" onclick="jsonIndir()">İndir (JSON)</button>
    </div>

    <script>
        // Global değişkenler
        let cekilisler = [];
        let cekilisSayisi = 0;
        const minSayi = 1;
        const maxSayi = 90;
        const sayiAdedi = 6;

        // Rastgele sayı üretme fonksiyonu (Benzersiz)
        function benzersizRastgeleSayilar() {
            const sayilar = new Set();
            while(sayilar.size < sayiAdedi) {
                const rastgele = Math.floor(Math.random() * (maxSayi - minSayi + 1)) + minSayi;
                sayilar.add(rastgele);
            }
            // Set'i diziye çevir ve sırala
            return Array.from(sayilar).sort((a, b) => a - b);
        }

        // Çekiliş Yapma Fonksiyonu
        function cekilisYap() {
            cekilisSayisi++;
            const yeniSayilar = benzersizRastgeleSayilar();

            // Veriyi kaydet
            const cekilisObj = {
                cekilisNo: cekilisSayisi,
                sayilar: yeniSayilar
            };
            cekilisler.push(cekilisObj);

            // Ekrana yazdır
            const resultsArea = document.getElementById('resultsArea');

            // İlk eklemede placeholder'ı temizle
            if (cekilisSayisi === 1) {
                resultsArea.innerHTML = '';
            }

            const div = document.createElement('div');
            div.className = 'result-item';
            div.innerHTML = `<strong>${cekilisSayisi}. Çekiliş:</strong> ${yeniSayilar.join(', ')}`;

            // En yeni en üstte olsun diye prepend kullanıyoruz
            resultsArea.prepend(div);
        }

        // Çekilişi Bitirme ve Frekans Hesaplama
        function cekilisiBitir() {
            if (cekilisler.length === 0) {
                alert("Henüz hiç çekiliş yapılmadı!");
                return;
            }

            // Frekans hesaplama
            const frekansMap = {};

            cekilisler.forEach(cekilis => {
                cekilis.sayilar.forEach(sayi => {
                    frekansMap[sayi] = (frekansMap[sayi] || 0) + 1;
                });
            });

            // Frekans raporunu hazırla ve göster
            const freqReportDiv = document.getElementById('frequencyReport');
            const freqGrid = document.getElementById('freqGrid');
            freqGrid.innerHTML = ''; // Temizle

            // 1'den 90'a kadar döngü, eğer frekans varsa göster
            for (let i = 1; i <= maxSayi; i++) {
                if (frekansMap[i]) {
                    const item = document.createElement('div');
                    item.className = 'freq-item';
                    item.innerHTML = `${i}: <span class="highlight">${frekansMap[i]}</span>`;
                    freqGrid.appendChild(item);
                }
            }

            freqReportDiv.style.display = 'block';

            // İndir butonunu göster
            document.getElementById('btnDownload').style.display = 'block';

            // Butonları devre dışı bırak (opsiyonel, kullanıcı deneyimi için)
            document.getElementById('btnDraw').disabled = true;
            document.getElementById('btnFinish').disabled = true;
            document.getElementById('btnFinish').style.opacity = '0.5';
            document.getElementById('btnFinish').style.cursor = 'not-allowed';
        }

        // JSON İndirme Fonksiyonu
        function jsonIndir() {
            const data = {
                cekilisler: cekilisler
            };

            const jsonString = JSON.stringify(data, null, 4); // 4 boşluk ile formatla
            const blob = new Blob([jsonString], { type: 'application/json' });
            const url = URL.createObjectURL(blob);

            const a = document.createElement('a');
            a.href = url;
            a.download = `cekilis_raporu_${new Date().getTime()}.json`;
            document.body.appendChild(a);
            a.click();

            // Temizlik
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        }
    </script>
</body>
</html>
